+fn norm(source: &str) -> String {
+    normalize_typescript_to_es2020(
+        source,
+        &TsNormalizationConfig::default(),
+        "trace",
+        "decision",
+        "policy",
+    )
+    .expect("normalization should pass")
+    .normalized_source
